public class PatternMomentumStrategyV2 {

    public static Strategy buildStrategy(BarSeries series) {
        ClosePriceIndicator closePrice = new ClosePriceIndicator(series);
        HighPriceIndicator highPrice = new HighPriceIndicator(series);
        LowPriceIndicator lowPrice = new LowPriceIndicator(series);
        VolumeIndicator volume = new VolumeIndicator(series);

        SMAIndicator ma5 = new SMAIndicator(closePrice, 5);
        SMAIndicator ma10 = new SMAIndicator(closePrice, 10);
        SMAIndicator ma20 = new SMAIndicator(closePrice, 20);
        SMAIndicator ma60 = new SMAIndicator(closePrice, 60);

        RSIIndicator rsi6 = new RSIIndicator(closePrice, 6);
        RSIIndicator rsi14 = new RSIIndicator(closePrice, 14);

        StochasticOscillatorKIndicator stochK = new StochasticOscillatorKIndicator(series, 14);

        SMAIndicator volMa5 = new SMAIndicator(volume, 5);
        SMAIndicator volMa20 = new SMAIndicator(volume, 20);

        Rule trendUp = new OverIndicatorRule(ma20, ma60);

        Rule priceBelowMa5 = new UnderIndicatorRule(closePrice, ma5);
        Rule priceBelowMa10 = new UnderIndicatorRule(closePrice, ma10);
        Rule rsi6Oversold = new UnderIndicatorRule(rsi6, DecimalNum.valueOf(30));
        Rule rsi6CrossDown30 = new CrossedDownIndicatorRule(rsi6, DecimalNum.valueOf(30));
        Rule stochKOversold = new UnderIndicatorRule(stochK, DecimalNum.valueOf(20));
        Rule priceAboveMa20 = new OverIndicatorRule(closePrice, ma20);

        Rule buyInUptrend = trendUp
                .and(priceBelowMa5.or(priceBelowMa10))
                .and(rsi6Oversold.or(rsi6CrossDown30).or(stochKOversold))
                .and(priceAboveMa20);

        Rule buyInDowntrend = priceBelowMa5
                .and(priceBelowMa10)
                .and(rsi6Oversold)
                .and(stochKOversold);

        Rule entryRule = buyInUptrend.or(buyInDowntrend);

        Rule priceAboveMa5 = new OverIndicatorRule(closePrice, ma5);
        Rule priceAboveMa10 = new OverIndicatorRule(closePrice, ma10);
        Rule rsi6Overbought = new OverIndicatorRule(rsi6, DecimalNum.valueOf(70));
        Rule stochKOverbought = new OverIndicatorRule(stochK, DecimalNum.valueOf(80));
        Rule priceBelowMa20Sell = new UnderIndicatorRule(closePrice, ma20);
        Rule trendDown = new UnderIndicatorRule(ma20, ma60);

        Rule sellStrong = priceAboveMa5
                .and(priceAboveMa10)
                .and(rsi6Overbought.or(stochKOverbought));

        Rule sellTrendReversal = trendDown
                .and(priceBelowMa20Sell);

        Rule exitRule = sellStrong.or(sellTrendReversal);

        return new BaseStrategy("PatternMomentumStrategyV2", entryRule, exitRule, 60);
    }
}

