public class MABullishAlignmentStrategy {
    public static Strategy buildStrategy(BarSeries series) {
        ClosePriceIndicator closePrice = new ClosePriceIndicator(series);

        SMAIndicator ma5 = new SMAIndicator(closePrice, 5);
        SMAIndicator ma10 = new SMAIndicator(closePrice, 10);
        SMAIndicator ma20 = new SMAIndicator(closePrice, 20);
        SMAIndicator ma60 = new SMAIndicator(closePrice, 60);

        RSIIndicator rsi14 = new RSIIndicator(closePrice, 14);

        Rule ma5AboveMa10 = new OverIndicatorRule(ma5, ma10);
        Rule ma10AboveMa20 = new OverIndicatorRule(ma10, ma20);
        Rule ma20AboveMa60 = new OverIndicatorRule(ma20, ma60);
        Rule bullishAlignment = ma5AboveMa10.and(ma10AboveMa20).and(ma20AboveMa60);

        Rule priceNearMa10 = new UnderIndicatorRule(closePrice, ma10);
        Rule priceNotTooFar = new OverIndicatorRule(closePrice, ma20);

        Rule rsiNeutral = new OverIndicatorRule(rsi14, series.numFactory().numOf(40));
        Rule rsiNotOverbought = new UnderIndicatorRule(rsi14, series.numFactory().numOf(70));

        Rule entryRule = bullishAlignment
            .and(priceNearMa10)
            .and(priceNotTooFar)
            .and(rsiNeutral)
            .and(rsiNotOverbought);

        Rule ma5BelowMa10 = new UnderIndicatorRule(ma5, ma10);
        Rule priceBelowMa20 = new UnderIndicatorRule(closePrice, ma20);
        Rule rsiOverbought = new OverIndicatorRule(rsi14, series.numFactory().numOf(70));

        Rule exitRule = ma5BelowMa10.or(priceBelowMa20).or(rsiOverbought);

        return new BaseStrategy("MABullishAlignmentStrategy", entryRule, exitRule, 60);
    }
}

