public class DoubleBottomStrategy {
    public static Strategy buildStrategy(BarSeries series) {
        ClosePriceIndicator closePrice = new ClosePriceIndicator(series);
        LowPriceIndicator lowPrice = new LowPriceIndicator(series);

        RSIIndicator rsi = new RSIIndicator(closePrice, 14);

        Rule firstBottom = new IsLowestRule(lowPrice, 20);

        Rule rsiAbove30 = new OverIndicatorRule(rsi, DecimalNum.valueOf(30));

        Rule entryRule = firstBottom.and(rsiAbove30);

        Rule priceBreakLow = new UnderIndicatorRule(closePrice, series.numFactory().numOf(series.getBar(series.getEndIndex() - 20).getLowPrice().doubleValue()));

        Rule exitRule = priceBreakLow;

        StopLossRule stopLoss = new StopLossRule(closePrice, DecimalNum.valueOf(5));
        exitRule = exitRule.or(stopLoss);

        return new BaseStrategy("DoubleBottomStrategy", entryRule, exitRule, 20);
    }
}

package com.tradingx.strategy;

import org.ta4j.core.*;
import org.ta4j.core.indicators.helpers.ClosePriceIndicator;
import org.ta4j.core.indicators.helpers.OpenPriceIndicator;
import org.ta4j.core.indicators.helpers.HighPriceIndicator;
import org.ta4j.core.indicators.helpers.PreviousValueIndicator;
import org.ta4j.core.indicators.averages.SMAIndicator;
import org.ta4j.core.rules.*;

public class GapUpStrategy {
    public static Strategy buildStrategy(BarSeries series) {
        ClosePriceIndicator closePrice = new ClosePriceIndicator(series);
        OpenPriceIndicator openPrice = new OpenPriceIndicator(series);
        HighPriceIndicator highPrice = new HighPriceIndicator(series);

        SMAIndicator ma20 = new SMAIndicator(closePrice, 20);
        SMAIndicator ma60 = new SMAIndicator(closePrice, 60);

        PreviousValueIndicator prevHigh = new PreviousValueIndicator(highPrice, 1);
        PreviousValueIndicator prevOpen = new PreviousValueIndicator(openPrice, 1);

        Rule gapUp = new OverIndicatorRule(openPrice, prevHigh);
        Rule gapNotTooBig = new UnderIndicatorRule(openPrice, series.numFactory().numOf(prevHigh.getValue(series.getEndIndex()).doubleValue() * 1.08));

        Rule trendUp = new OverIndicatorRule(ma20, ma60);
        Rule priceAboveMa20 = new OverIndicatorRule(closePrice, ma20);

        Rule priceNearGapSupport = new OverIndicatorRule(closePrice, prevHigh);

        Rule entryRule = gapUp
            .and(gapNotTooBig)
            .and(trendUp)
            .and(priceAboveMa20)
            .and(priceNearGapSupport);

        Rule priceBackToGap = new UnderIndicatorRule(closePrice, prevOpen);
        Rule stopLoss = new UnderIndicatorRule(closePrice, prevHigh);

        Rule exitRule = priceBackToGap.or(stopLoss);

        return new BaseStrategy("GapUpStrategy", entryRule, exitRule, 60);
    }
}

package com.tradingx.strategy;

import org.ta4j.core.*;
import org.ta4j.core.indicators.helpers.ClosePriceIndicator;
import org.ta4j.core.indicators.helpers.VolumeIndicator;
import org.ta4j.core.indicators.averages.SMAIndicator;
import org.ta4j.core.rules.*;

public class VolumeSurgeStrategy {
    public static Strategy buildStrategy(BarSeries series) {
        ClosePriceIndicator closePrice = new ClosePriceIndicator(series);
        VolumeIndicator volume = new VolumeIndicator(series);

        SMAIndicator sma10 = new SMAIndicator(closePrice, 10);
        SMAIndicator sma20 = new SMAIndicator(closePrice, 20);
        SMAIndicator sma60 = new SMAIndicator(closePrice, 60);
        SMAIndicator volMa5 = new SMAIndicator(volume, 5);

        Rule volumeSurged = new OverIndicatorRule(volume, volMa5);
        Rule priceAboveMa20 = new OverIndicatorRule(closePrice, sma20);
        Rule trendUp = new OverIndicatorRule(sma20, sma60);
        Rule newHigh = new IsHighestRule(closePrice, 20);

        Rule entryRule = volumeSurged.and(priceAboveMa20).and(trendUp).and(newHigh);

        Rule priceBelowMa10 = new UnderIndicatorRule(closePrice, sma10);
        Rule volumeDeclined = new UnderIndicatorRule(volume, volMa5);

        Rule exitRule = priceBelowMa10.or(volumeDeclined);

        return new BaseStrategy("VolumeSurgeStrategy", entryRule, exitRule, 60);
    }
}
